INSERT INTO public.agent_config_revisions VALUES ('6f61f79a-7f9d-4803-8e4c-d449361d5d16', 'd614ecc3-b46c-47cc-af90-7d2b33e0a47e', '3071507e-da74-46bd-b521-cf16eb00f9b4', 'f17e51ca-4c4c-47bb-8c4b-84516ab5505c', NULL, 'instructions_path_patch', NULL, '["adapterConfig"]', '{"name": "Frontend Engineer", "role": "engineer", "title": "Frontend UI Engineer", "metadata": null, "reportsTo": "f17e51ca-4c4c-47bb-8c4b-84516ab5505c", "adapterType": "claude_local", "capabilities": "Builds and maintains frontend user interfaces using JavaScript, TypeScript, CSS, and modern frameworks (React, Vue, Next.js, Tailwind). Follows test-driven development (TDD) patterns — writes tests first, then implements. Always verifies changes pass tests and linting before committing. Communicates with Engineering Manager for task clarification and progress updates. Coordinates with Backend Engineers before implementing features that require API integration or backend cooperation. Produces accessible, responsive, and performant UI components.", "adapterConfig": {"graceSec": 15, "timeoutSec": 0, "maxTurnsPerRun": 200, "instructionsBundleMode": "managed", "dangerouslySkipPermissions": true}, "runtimeConfig": {"heartbeat": {"enabled": true, "intervalSec": 1800, "wakeOnDemand": true, "maxConcurrentRuns": 1}}, "budgetMonthlyCents": 0}', '{"name": "Frontend Engineer", "role": "engineer", "title": "Frontend UI Engineer", "metadata": null, "reportsTo": "f17e51ca-4c4c-47bb-8c4b-84516ab5505c", "adapterType": "claude_local", "capabilities": "Builds and maintains frontend user interfaces using JavaScript, TypeScript, CSS, and modern frameworks (React, Vue, Next.js, Tailwind). Follows test-driven development (TDD) patterns — writes tests first, then implements. Always verifies changes pass tests and linting before committing. Communicates with Engineering Manager for task clarification and progress updates. Coordinates with Backend Engineers before implementing features that require API integration or backend coo