INSERT INTO public.agent_config_revisions VALUES ('ada927c0-d0fe-4b9e-8799-5acaa532b20a', 'd614ecc3-b46c-47cc-af90-7d2b33e0a47e', 'beb6459f-8b56-4270-a1e8-6043dd575548', 'f17e51ca-4c4c-47bb-8c4b-84516ab5505c', NULL, 'instructions_path_patch', NULL, '["adapterConfig"]', '{"name": "Backend Engineer", "role": "engineer", "title": "Backend Engineer", "metadata": null, "reportsTo": "f17e51ca-4c4c-47bb-8c4b-84516ab5505c", "adapterType": "claude_local", "capabilities": "Builds and maintains server-side applications, APIs, database schemas, business logic, integrations, infrastructure, and backend performance. Uses Node.js, Python, SQL, and modern backend frameworks. Follows test-driven development (TDD) patterns — writes tests first, then implements. Always verifies changes pass tests and linting before committing. Communicates with Engineering Manager for task clarification and progress updates. Coordinates with Frontend Engineers on API contracts and integration points. Produces reliable, secure, and performant backend services.", "adapterConfig": {"graceSec": 15, "timeoutSec": 0, "maxTurnsPerRun": 200, "instructionsBundleMode": "managed", "dangerouslySkipPermissions": true}, "runtimeConfig": {"heartbeat": {"enabled": true, "intervalSec": 1800, "wakeOnDemand": true, "maxConcurrentRuns": 1}}, "budgetMonthlyCents": 0}', '{"name": "Backend Engineer", "role": "engineer", "title": "Backend Engineer", "metadata": null, "reportsTo": "f17e51ca-4c4c-47bb-8c4b-84516ab5505c", "adapterType": "claude_local", "capabilities": "Builds and maintains server-side applications, APIs, database schemas, business logic, integrations, infrastructure, and backend performance. Uses Node.js, Python, SQL, and modern backend frameworks. Follows test-driven development (TDD) patterns — writes tests first, then implements. Always verifies changes pass tests and linting before committing. Communicates with Engineering Manager for task clarification and progress updates. Coordinates with Frontend Engineers on API contracts and integration points. Produces reliable, secure, and performant backend services.", "adapterConfig": {"graceSec": 15, "timeoutSec": 0, "maxTurnsPerRun": 200, "instructionsFilePath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/beb6459f-8b56-4270-a1e8-6043dd575548/instructions/AGENTS.md", "instructionsRootPath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/beb6459f-8b56-4270-a1e8-6043dd575548/instructions", "instructionsEntryFile": "AGENTS.md", "instructionsBundleMode": "managed", "dangerouslySkipPermissions": true}, "runtimeConfig": {"heartbeat": {"enabled": true, "intervalSec": 1800, "wakeOnDemand": true, "maxConcurrentRuns": 1}}, "budgetMonthlyCents": 0}', '2026-03-30 14:36:22.739062+00');
INSERT INTO public.agent_config_revisions VALUES ('914042ae-8dcf-4723-807d-5d02fce2a0b7', 'd614ecc3-b46c-47cc-af90-7d2b33e0a47e', '1a865d2d-3b6d-4ac6-b3c4-4ccfbb9c8a30', '635f3a34-c54a-4b59-ab25-e73fc30b6cf3', NULL, 'instructions_path_patch', NULL, '["adapterConfig"]', '{"name": "General Counsel", "role": "general", "title": "General Counsel & Chief Legal Officer", "metadata": null, "reportsTo": "635f3a34-c54a-4b59-ab25-e73fc30b6cf3", "adapterType": "claude_local", "capabilities": "Handles all legal procedures, proceedings, and matters. Composes, edits, evaluates, and reviews legal documents including contracts, agreements, policies, and compliance frameworks. Monitors regulatory compliance and enforces legal standards across the organization. Protects intellectual property and proprietary information. Evaluates and improves legal structure and corporate governance. Has authority to halt any activity deemed illegal or non-compliant until the CEO reviews and provides clearance. Maintains strict confidentiality — does not disclose work product or legal matters to other agents. Reports exclusively to the CEO.", "adapterConfig": {"graceSec": 15, "timeoutSec": 0, "maxTurnsPerRun": 200, "instructionsBundleMode": "managed", "dangerouslySkipPermissions": true}, "runtimeConfig": {"heartbeat": {"enabled": true, "intervalSec": 1800, "wakeOnDemand": true, "maxConcurrentRuns": 1}}, "budgetMonthlyCents": 0}', '{"name": "General Counsel", "role": "general", "title": "General Counsel & Chief Legal Officer", "metadata": null, "reportsTo": "635f3a34-c54a-4b59-ab25-e73fc30b6cf3", "adapterType": "claude_local", "capabilities": "Handles all legal procedures, proceedings, and matters. Composes, edits, evaluates, and reviews legal documents including contracts, agreements, policies, and compliance frameworks. Monitors regulatory compliance and enforces legal standards across the organization. Protects intellectual property and proprietary information. Evaluates and improves legal structur